from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a fluent description from a list of triples about a monument."""
    if not triples:
        return ""
    # Aggregate information assuming all triples refer to the same subject
    info: dict[str, str] = {}
    for t in triples:
        info[t.predicate] = t.object
    subject = triples[0].subject

    parts: list[str] = []

    # Basic identification
    if "category" in info:
        parts.append(f"{subject} is a {info['category']}")
    else:
        parts.append(f"{subject} is a monument")

    # Hierarchical location information
    location_elements = []
    for key in ("municipality", "location", "district", "state", "country"):
        if key in info:
            location_elements.append(info[key])
    if location_elements:
        parts.append("located in " + ", ".join(location_elements))

    # Dates: established / founding / inauguration
    date_map = {
        "established": "established on",
        "foundingDate": "founded on",
        "inaugurationDate": "inaugurated on",
    }
    for pred, phr in date_map.items():
        if pred in info:
            parts.append(f"{phr} {info[pred]}")

    # Dedicated to
    if "dedicatedTo" in info:
        parts.append(f"dedicated to {info['dedicatedTo']}")

    # Designer
    if "designer" in info:
        parts.append(f"designed by {info['designer']}")

    # Material
    if "material" in info:
        parts.append(f"made of {info['material']}")

    # Ownership
    if "owner" in info:
        parts.append(f"owned by {info['owner']}")
    elif "owningOrganisation" in info:
        parts.append(f"owned by {info['owningOrganisation']}")

    # Combine all parts into a single fluent sentence
    sentence = "; ".join(parts) + "."
    return sentence

# EVOLVE-BLOCK-END

